export enum AppSection {
  NEWS = 'TIN TỨC',
  TREE = 'PHẢ ĐỒ',
  CHRONICLES = 'PHẢ KỸ',
  ANCESTRAL_HOUSE = 'TỪ ĐƯỜNG',
  REGULATIONS = 'TỘC ƯỚC',
  EVENTS = 'SỰ KIỆN'
}

export type AppTheme = 'classic' | 'tet';

export interface Spouse {
  id: string;
  name: string;
  birthDate?: string;
  deathDate?: string;
}

export interface FamilyMember {
  id: string;
  name: string;
  generation: number;
  birthDate?: string;
  deathDate?: string;
  lunarDeathDate?: string;
  spouseName?: string; // Legacy
  spouseBirthDate?: string; // Legacy
  spouseDeathDate?: string; // Legacy
  spouses?: Spouse[]; // New multi-spouse support
  children?: FamilyMember[];
  bio?: string;
  isMale: boolean;
  parentName?: string;
}

export interface NewsItem {
  id: string;
  title: string;
  date: string;
  summary: string;
  content: string;
  imageUrl?: string;
}

export type EventType = 'giỗ' | 'sinh nhật' | 'họp mặt' | 'khác';

export interface EventItem {
  id: string;
  title: string;
  solarDate: string;
  lunarDateLabel?: string;
  type: EventType;
  description?: string;
}

export interface AppData {
  news: NewsItem[];
  familyTree: FamilyMember;
  events: EventItem[];
  bannerUrl: string;
  address: string;
  historyText: string;
  ancestralHouseText: string;
  regulations: string[];
  clanName: string;
  lastUpdated: string;
  theme?: AppTheme;
}

import React, { useState, useRef, useEffect, useMemo, useCallback } from 'react';
import { FamilyMember, Spouse } from '../types';
import * as htmlToImage from 'https://esm.sh/html-to-image';

interface MemberNodeProps {
  member: FamilyMember;
  isAdmin: boolean;
  searchQuery: string;
  onEdit?: (member: FamilyMember) => void;
  onDelete?: (id: string) => void;
  onAddChild?: (parent: FamilyMember) => void;
}

const MemberNode: React.FC<MemberNodeProps> = ({ member, isAdmin, searchQuery, onEdit, onDelete, onAddChild }) => {
  const [isExpanded, setIsExpanded] = useState(true);
  const hasChildren = member.children && member.children.length > 0;

  // Combine legacy spouse and multi-spouses
  const allSpouses = useMemo(() => {
    const list: Partial<Spouse>[] = [...(member.spouses || [])];
    if (member.spouseName && !list.some(s => s.name === member.spouseName)) {
      list.unshift({ id: 'legacy', name: member.spouseName, deathDate: member.spouseDeathDate });
    }
    return list;
  }, [member.spouses, member.spouseName, member.spouseDeathDate]);

  const containsMatch = useMemo(() => {
    if (!searchQuery) return false;
    const q = searchQuery.toLowerCase();

    const checkNode = (node: FamilyMember): boolean => {
      if (node.name.toLowerCase().includes(q)) return true;
      if (node.spouses?.some(s => s.name.toLowerCase().includes(q))) return true;
      if (node.spouseName?.toLowerCase().includes(q)) return true;
      if (node.children) return node.children.some(checkNode);
      return false;
    };

    return checkNode(member);
  }, [member, searchQuery]);

  useEffect(() => {
    if (searchQuery && containsMatch) {
      setIsExpanded(true);
    }
  }, [searchQuery, containsMatch]);

  const toggleExpand = () => {
    setIsExpanded(!isExpanded);
  };

  const isCompact = member.generation >= 4;
  const isGen1To2 = member.generation === 1;

  const isNameMatched = searchQuery && member.name.toLowerCase().includes(searchQuery.toLowerCase());

  const renderVerticalName = (name: string) => {
    return name.split(' ').map((word, i) => (
      <span key={i} className="block leading-tight">{word}</span>
    ));
  };

  const nameFontSizeClass = isCompact 
    ? 'text-[13px] leading-tight py-1' 
    : (isGen1To2 ? 'text-2xl md:text-3xl' : 'text-lg md:text-xl');

  return (
    <div className="flex flex-col items-center transition-all duration-500 w-full">
      <div className="relative group flex flex-col items-center justify-center">
        <div className="flex flex-row items-start gap-2 relative z-10">
          {/* Main Member Node */}
          <div className={`
            relative transition-all duration-500 transform 
            ${isCompact 
              ? 'w-16 p-3 rounded-2xl border-2 bg-white shadow-xl' 
              : 'w-48 md:w-64 p-4 md:p-6 rounded-[1.5rem] md:rounded-[2rem] border-4 bg-white shadow-2xl'
            }
            ${member.isMale 
              ? 'border-red-900/40 shadow-red-900/5' 
              : 'border-pink-900/40 shadow-pink-900/5'
            }
            ${isGen1To2 ? 'ring-8 ring-red-900/5 ring-offset-4 border-red-900 bg-red-50/50' : ''}
            ${isNameMatched ? 'ring-4 ring-yellow-400 border-yellow-500 scale-105 z-20 !shadow-[0_0_30px_rgba(234,179,8,0.5)]' : 'group-hover:-translate-y-1 md:group-hover:-translate-y-2'}
          `}>
            {!isCompact && (
              <div className={`absolute -top-3 left-1/2 -translate-x-1/2 px-3 py-0.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-sm z-20 ${member.isMale ? 'bg-red-900 text-white' : 'bg-pink-600 text-white'}`}>
                {member.isMale ? 'Nam' : 'Nữ'}
              </div>
            )}

            {isAdmin && (
              <div className="absolute -top-4 -left-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-all z-30">
                <button 
                  onClick={(e) => { e.stopPropagation(); onEdit?.(member); }}
                  className={`bg-yellow-500 text-white rounded-full p-2 shadow-xl hover:bg-yellow-600 ${isCompact ? 'scale-75' : ''}`}
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" /></svg>
                </button>
                {!isGen1To2 && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); if(confirm(`Xóa ${member.name} khỏi phả đồ?`)) onDelete?.(member.id); }}
                    className={`bg-red-600 text-white rounded-full p-2 shadow-xl hover:bg-red-700 ${isCompact ? 'scale-75' : ''}`}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                  </button>
                )}
              </div>
            )}

            <div className={`
              font-bold text-red-950 font-traditional text-center tracking-tight
              ${nameFontSizeClass}
              ${isNameMatched ? 'text-yellow-700' : ''}
            `}>
              {isCompact ? renderVerticalName(member.name) : member.name}
            </div>

            {!isCompact && (
              <div className="mt-2 md:mt-4 space-y-1 text-center">
                {member.birthDate && (
                  <div className="text-[9px] md:text-[10px] text-gray-500 font-bold uppercase tracking-wider">
                    Sinh: <span className="text-red-900/60 italic">{member.birthDate}</span>
                  </div>
                )}
                {(member.deathDate || member.lunarDeathDate) && (
                  <div className="text-[9px] md:text-[10px] text-red-700/80 font-black uppercase tracking-wider">
                    Mất: <span className="italic">{member.lunarDeathDate || member.deathDate} (ÂL)</span>
                  </div>
                )}
                <div className={`text-[8px] md:text-[9px] font-black uppercase tracking-[0.2em] md:tracking-[0.3em] rounded-full py-1 mt-2 md:mt-4 inline-block px-3 md:px-4 ${isGen1To2 ? 'bg-red-900 text-gold shadow-lg' : 'bg-red-50 text-red-900/60'}`}>
                  {isGen1To2 ? 'Cụ Tổ' : `Đời ${member.generation}`}
                </div>
              </div>
            )}

            {isAdmin && (
              <button 
                onClick={(e) => { e.stopPropagation(); onAddChild?.(member); }}
                className={`absolute -bottom-4 -right-4 bg-red-800 text-white rounded-full p-2 shadow-xl hover:bg-red-950 hover:scale-110 z-30 transition-all ${isCompact ? 'scale-75' : ''}`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" /></svg>
              </button>
            )}
          </div>

          {/* Multiple Spouses */}
          {allSpouses.map((spouse, idx) => {
            const isSpouseMatched = searchQuery && spouse.name?.toLowerCase().includes(searchQuery.toLowerCase());
            return (
              <div key={spouse.id || idx} className={`
                relative transition-all duration-500 transform 
                ${isCompact 
                  ? 'w-16 p-3 rounded-2xl border-2 border-dashed bg-white shadow-lg' 
                  : 'w-48 md:w-64 p-4 md:p-6 rounded-[1.5rem] md:rounded-[2rem] border-4 border-dashed bg-pink-50/20 shadow-xl'
                }
                border-pink-900/20
                ${isSpouseMatched ? 'ring-4 ring-yellow-400 border-yellow-500 scale-105 z-20 !shadow-[0_0_30px_rgba(234,179,8,0.5)]' : 'group-hover:-translate-y-1 md:group-hover:-translate-y-2'}
              `}>
                <div className={`
                  font-bold text-pink-950 font-traditional text-center tracking-tight
                  ${nameFontSizeClass}
                  ${isSpouseMatched ? 'text-yellow-700' : ''}
                `}>
                  {isCompact ? renderVerticalName(spouse.name || '') : spouse.name}
                </div>
                {!isCompact && (
                  <div className="mt-2 md:mt-4 text-center">
                    <div className="text-[8px] md:text-[9px] text-pink-900/60 font-black uppercase tracking-[0.2em]">Vợ / Chồng {allSpouses.length > 1 ? idx + 1 : ''}</div>
                    {spouse.deathDate && (
                      <div className="text-[8px] md:text-[9px] text-pink-700/60 font-bold mt-1">
                        Mất: {spouse.deathDate} (ÂL)
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {hasChildren && (
          <button
            onClick={toggleExpand}
            className={`
              absolute left-1/2 -translate-x-1/2 z-20 w-8 h-8 rounded-full border-2 shadow-2xl flex items-center justify-center transition-all duration-300
              ${isCompact ? '-bottom-5 scale-90' : '-bottom-4'}
              ${isExpanded ? 'bg-red-950 border-gold text-gold rotate-0' : 'bg-gold border-red-950 text-red-950 rotate-180'}
            `}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M14.707 12.707a1 1 0 01-1.414 0L10 9.414l-3.293 3.293a1 1 0 01-1.414-1.414l4-4a1 1 0 011.414 0l4 4a1 1 0 010 1.414z" clipRule="evenodd" /></svg>
          </button>
        )}
      </div>

      {hasChildren && isExpanded && (
        <div className="relative mt-12 md:mt-16 animate-fadeIn w-full flex flex-col items-center">
          <div className={`absolute top-[-48px] md:top-[-64px] left-1/2 -translate-x-1/2 bg-red-900/20 -z-10 w-[4px] h-[48px] md:h-[64px] ${isGen1To2 ? 'w-[6px] bg-red-900/40' : ''}`} />

          <div className="flex flex-row justify-center relative w-full pt-0">
             {member.children?.map((child, index) => {
                const isFirst = index === 0;
                const isLast = index === (member.children?.length ?? 0) - 1;
                const childIsCompact = child.generation >= 4;

                return (
                  <div key={child.id} className={`relative flex flex-col items-center flex-1 ${childIsCompact ? 'px-1' : 'px-4 md:px-6'}`}>
                     {member.children && member.children.length > 1 && (
                        <div className={`
                          absolute top-0 h-[4px] bg-red-900/20
                          ${isFirst ? 'left-1/2 right-0' : isLast ? 'left-0 right-1/2' : 'left-0 right-0'}
                        `}></div>
                     )}
                     <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[4px] h-6 md:h-8 bg-red-900/20 -z-10"></div>
                     <div className="mt-6 md:mt-8 w-full flex justify-center">
                       <MemberNode 
                         member={child} 
                         isAdmin={isAdmin} 
                         searchQuery={searchQuery}
                         onEdit={onEdit} 
                         onDelete={onDelete}
                         onAddChild={onAddChild} 
                       />
                     </div>
                  </div>
                );
             })}
          </div>
        </div>
      )}
    </div>
  );
};

interface FamilyTreeProps {
  root: FamilyMember;
  isAdmin: boolean;
  onEditMember: (member: FamilyMember) => void;
  onDeleteMember: (id: string) => void;
  onAddChild: (parent: FamilyMember) => void;
}

const FamilyTree: React.FC<FamilyTreeProps> = ({ root, isAdmin, onEditMember, onDeleteMember, onAddChild }) => {
  const [scale, setScale] = useState(0.6);
  const [searchQuery, setSearchQuery] = useState('');
  const [isPanelOpen, setIsPanelOpen] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);
  const treeRef = useRef<HTMLDivElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);

  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });
  const [isExporting, setIsExporting] = useState(false);
  const initialPinchDistRef = useRef<number | null>(null);

  const handleZoom = useCallback((delta: number, clientX: number, clientY: number) => {
    if (!containerRef.current) return;
    const container = containerRef.current;
    const rect = container.getBoundingClientRect();
    const mouseX = clientX - rect.left;
    const mouseY = clientY - rect.top;
    const contentX = (mouseX + container.scrollLeft) / scale;
    const contentY = (mouseY + container.scrollTop) / scale;

    setScale(prevScale => {
      const newScale = Math.min(Math.max(prevScale * (1 + delta), 0.1), 3.0);
      requestAnimationFrame(() => {
        container.scrollLeft = contentX * newScale - mouseX;
        container.scrollTop = contentY * newScale - mouseY;
      });
      return newScale;
    });
  }, [scale]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const onWheel = (e: WheelEvent) => {
      e.preventDefault();
      const delta = -e.deltaY * 0.001;
      handleZoom(delta, e.clientX, e.clientY);
    };
    container.addEventListener('wheel', onWheel, { passive: false });
    return () => container.removeEventListener('wheel', onWheel);
  }, [handleZoom]);

  const handleMouseDown = (e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('button, input')) return;
    setIsDragging(true);
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !containerRef.current) return;
    const dx = e.clientX - lastMousePos.x;
    const dy = e.clientY - lastMousePos.y;
    containerRef.current.scrollLeft -= dx;
    containerRef.current.scrollTop -= dy;
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => setIsDragging(false);

  const handleTouchStart = (e: React.TouchEvent) => {
    if (e.touches.length === 2) {
      const dist = Math.hypot(e.touches[0].pageX - e.touches[1].pageX, e.touches[0].pageY - e.touches[1].pageY);
      initialPinchDistRef.current = dist;
    } else if (e.touches.length === 1) {
      setLastMousePos({ x: e.touches[0].clientX, y: e.touches[0].clientY });
      setIsDragging(true);
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (e.touches.length === 2 && initialPinchDistRef.current !== null) {
      e.preventDefault();
      const dist = Math.hypot(e.touches[0].pageX - e.touches[1].pageX, e.touches[0].pageY - e.touches[1].pageY);
      const centerX = (e.touches[0].clientX + e.touches[1].clientX) / 2;
      const centerY = (e.touches[0].clientY + e.touches[1].clientY) / 2;
      const zoomFactor = (dist / initialPinchDistRef.current) - 1;
      handleZoom(zoomFactor * 0.5, centerX, centerY);
      initialPinchDistRef.current = dist;
    } else if (e.touches.length === 1 && isDragging && containerRef.current) {
      const touch = e.touches[0];
      const dx = touch.clientX - lastMousePos.x;
      const dy = touch.clientY - lastMousePos.y;
      containerRef.current.scrollLeft -= dx;
      containerRef.current.scrollTop -= dy;
      setLastMousePos({ x: touch.clientX, y: touch.clientY });
    }
  };

  const handleTouchEnd = () => {
    initialPinchDistRef.current = null;
    setIsDragging(false);
  };

  const handleResetView = useCallback(() => {
    if (!containerRef.current || !treeRef.current) return;
    const isMobile = window.innerWidth < 768;
    const initialScale = isMobile ? 0.3 : 0.6;
    setScale(initialScale);
    setTimeout(() => {
      if (!containerRef.current || !treeRef.current) return;
      const cw = containerRef.current.clientWidth;
      const tw = treeRef.current.offsetWidth * initialScale;
      containerRef.current.scrollLeft = (tw - cw) / 2;
      containerRef.current.scrollTop = 0;
    }, 50);
  }, []);

  useEffect(() => {
    const timer = setTimeout(handleResetView, 300);
    return () => clearTimeout(timer);
  }, [handleResetView]);

  const toggleFullScreen = () => {
    if (!wrapperRef.current) return;
    if (!document.fullscreenElement) {
      wrapperRef.current.requestFullscreen().catch(err => console.error(err));
    } else {
      document.exitFullscreen();
    }
  };

  const handleExportPNG = async () => {
    if (!treeRef.current) return;
    try {
      setIsExporting(true);
      const originalScale = scale;
      setScale(1);
      await new Promise(resolve => setTimeout(resolve, 800));
      const dataUrl = await htmlToImage.toPng(treeRef.current, {
        backgroundColor: '#fdf6e3',
        pixelRatio: 2,
        style: { transform: 'scale(1)', transformOrigin: 'top center' }
      });
      const link = document.createElement('a');
      link.download = `phado-le-${new Date().toISOString().split('T')[0]}.png`;
      link.href = dataUrl;
      link.click();
      setScale(originalScale);
    } catch (err) {
      console.error('Export error:', err);
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div 
      ref={wrapperRef}
      className={`relative w-full overflow-hidden bg-white/60 backdrop-blur-xl rounded-[2rem] md:rounded-[3rem] border-2 border-red-900/5 shadow-2xl transition-all duration-500 ${isFullscreen ? 'fixed inset-0 z-[1000] rounded-none border-none' : 'h-[70vh] md:min-h-[850px]'} flex flex-col`}
    >
      {isExporting && (
        <div className="fixed inset-0 z-[500] bg-black/60 backdrop-blur-md flex flex-col items-center justify-center animate-fadeIn">
          <div className="bg-white p-12 rounded-[2rem] shadow-2xl border-8 border-double border-red-900 flex flex-col items-center gap-6">
            <div className="w-16 h-16 border-4 border-red-900 border-t-gold rounded-full animate-spin"></div>
            <p className="font-black text-red-950 uppercase tracking-[0.3em] text-sm">Đang họa Phả Đồ...</p>
          </div>
        </div>
      )}

      <div className={`controls-panel absolute top-4 right-4 md:top-10 md:right-10 z-50 flex flex-col items-end gap-3`}>
        <div className="flex gap-2">
           <button onClick={toggleFullScreen} className="w-10 h-10 md:w-12 md:h-12 bg-white text-red-950 rounded-full flex items-center justify-center shadow-lg border border-red-900/10 hover:scale-110 active:scale-95 transition-all">
             {isFullscreen ? '↙️' : '↗️'}
           </button>
           <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="w-10 h-10 md:w-12 md:h-12 bg-red-950 text-gold rounded-full flex items-center justify-center shadow-lg border border-gold/30 hover:scale-110 active:scale-95 transition-all">
             {isPanelOpen ? '✖️' : '⚙️'}
           </button>
        </div>

        {isPanelOpen && (
          <div className="bg-white/95 backdrop-blur-2xl shadow-2xl rounded-3xl border border-red-900/10 p-5 w-64 md:w-72 flex flex-col gap-5 animate-fadeIn">
             <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-red-950/40 tracking-widest">Tìm kiếm</label>
                <input type="text" placeholder="Nhập tên..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-red-50/50 border-2 border-red-900/5 rounded-xl px-4 py-2 text-sm font-bold text-red-950 outline-none" />
             </div>
             <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-red-950/40 tracking-widest">Tỉ lệ: {Math.round(scale * 100)}%</label>
                <div className="flex gap-2">
                   <button onClick={() => handleZoom(-0.1, window.innerWidth/2, window.innerHeight/2)} className="flex-1 bg-red-50 text-red-900 py-2 rounded-xl font-bold hover:bg-red-100">-</button>
                   <button onClick={() => handleZoom(0.1, window.innerWidth/2, window.innerHeight/2)} className="flex-1 bg-red-50 text-red-900 py-2 rounded-xl font-bold hover:bg-red-100">+</button>
                   <button onClick={handleResetView} className="bg-red-950 text-gold px-4 rounded-xl">⟲</button>
                </div>
             </div>
             <button onClick={handleExportPNG} className="w-full bg-primary text-gold py-3 rounded-xl font-black text-[10px] uppercase tracking-widest shadow-md">Xuất ảnh PNG</button>
          </div>
        )}
      </div>

      <div ref={containerRef} onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp} onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd} className={`w-full flex-1 overflow-auto scrollbar-hide select-none ${isDragging ? 'cursor-grabbing' : 'cursor-grab'}`}>
        <div ref={treeRef} style={{ transform: `scale(${scale})`, transformOrigin: '0 0', width: 'fit-content', minWidth: '100%', padding: '200px 100vw' }} className="relative transition-transform duration-75 ease-out">
          <div className="flex justify-center w-full">
            <MemberNode member={root} isAdmin={isAdmin} searchQuery={searchQuery} onEdit={onEditMember} onDelete={onDeleteMember} onAddChild={onAddChild} />
          </div>
        </div>
      </div>
      <div className="bg-white/90 border-t border-red-900/5 px-6 py-2 flex justify-between items-center text-[9px] font-bold text-red-950/30 uppercase tracking-widest">
        <span>Lăn chuột hoặc Pinch để Zoom • Kéo để di chuyển • Xoá thành viên (Admin)</span>
        <span className="hidden md:block">Gia Tộc Họ Lê © 2024</span>
      </div>
    </div>
  );
};

export default FamilyTree;

import React, { useState, useEffect, useMemo } from 'react';
import { AppSection, FamilyMember, NewsItem, EventItem, AppData, Spouse } from './types';
import Navigation from './components/Navigation';
import FamilyTree from './components/FamilyTree';
import Events from './components/Events';
import AdminPanel from './components/AdminPanel';
import { PersistenceService } from './services/persistenceService';
import { 
  CLAN_NAME, CLAN_ADDRESS, SAMPLE_NEWS, SAMPLE_FAMILY_TREE 
} from './constants';

const DEFAULT_CLOUD_LINK = "https://docs.google.com/document/d/17fVZaOxx8s-gS3tFE3nj1fdmSJdYWw0mi_ar45TUoQw/edit?usp=sharing";

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<AppSection>(AppSection.EVENTS);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
  const [cloudLink, setCloudLink] = useState<string>(() => localStorage.getItem('cloud_data_link') || DEFAULT_CLOUD_LINK);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [password, setPassword] = useState('');
  const [editingMember, setEditingMember] = useState<FamilyMember | null>(null);
  const [editingNews, setEditingNews] = useState<NewsItem | null>(null);
  const [newsToDelete, setNewsToDelete] = useState<NewsItem | null>(null);
  const [isEditingText, setIsEditingText] = useState(false);
  const [showBannerEdit, setShowBannerEdit] = useState(false);

  const [appData, setAppData] = useState<AppData>(() => {
    const saved = PersistenceService.loadLocal();
    if (saved) return saved;
    return {
      news: SAMPLE_NEWS,
      familyTree: SAMPLE_FAMILY_TREE,
      events: [{ id: 'e1', title: 'Họp Mặt Đầu Xuân', solarDate: '2025-02-15', type: 'họp mặt' }],
      bannerUrl: "https://images.unsplash.com/photo-1577908581023-95245842c8d2?auto=format&fit=crop&q=80&w=2000",
      address: CLAN_ADDRESS,
      historyText: "Lịch sử dòng họ Lê là một hành trình dài...",
      ancestralHouseText: "Từ đường là nơi thờ tự linh thiêng...",
      regulations: ["Tôn thờ tổ tiên...", "Đoàn kết..."],
      clanName: CLAN_NAME,
      lastUpdated: new Date().toISOString(),
      theme: 'tet'
    };
  });

  const derivedGioEvents = useMemo(() => {
    const gioList: EventItem[] = [];
    const traverse = (member: FamilyMember) => {
      if (member.lunarDeathDate || member.deathDate) {
        gioList.push({ id: `gio-${member.id}`, title: `Giỗ cụ ${member.name}`, solarDate: '', lunarDateLabel: member.lunarDeathDate || member.deathDate, type: 'giỗ' });
      }
      const spouses = member.spouses || (member.spouseName ? [{ id: 'legacy', name: member.spouseName, deathDate: member.spouseDeathDate }] : []);
      spouses.forEach((s, idx) => {
        if (s.deathDate) {
          gioList.push({ id: `gio-s-${member.id}-${idx}`, title: `Giỗ cụ bà (Vợ ${idx + 1} cụ ${member.name})`, solarDate: '', lunarDateLabel: s.deathDate, type: 'giỗ' });
        }
      });
      member.children?.forEach(traverse);
    };
    traverse(appData.familyTree);
    return gioList;
  }, [appData.familyTree]);

  const allEvents = useMemo(() => [...appData.events, ...derivedGioEvents], [appData.events, derivedGioEvents]);

  useEffect(() => { document.body.className = appData.theme === 'classic' ? 'theme-classic' : ''; }, [appData.theme]);
  useEffect(() => { PersistenceService.saveLocal(appData); }, [appData]);

  const handleSync = async () => {
    setIsSyncing(true);
    const cloudData = await PersistenceService.fetchFromCloud(cloudLink);
    if (cloudData) { setAppData(cloudData); showToast("Đồng bộ thành công!"); }
    setIsSyncing(false);
  };

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3500);
  };

  const updateData = (updates: Partial<AppData>) => {
    setAppData(prev => ({ ...prev, ...updates, lastUpdated: new Date().toISOString() }));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin123') { setIsAdmin(true); setShowLogin(false); setPassword(''); showToast("Chế độ Quản trị đã mở"); }
    else showToast("Sai mật khẩu!", "error");
  };

  const deleteMember = (id: string) => {
    const removeNode = (node: FamilyMember): FamilyMember | null => {
      if (node.id === id) return null;
      if (node.children) {
        return { ...node, children: node.children.map(removeNode).filter(Boolean) as FamilyMember[] };
      }
      return node;
    };
    const newTree = removeNode(appData.familyTree);
    if (newTree) {
      updateData({ familyTree: newTree });
      showToast("Đã xoá thành viên");
    } else {
      showToast("Không thể xoá Cụ Tổ!", "error");
    }
  };

  const renderSection = () => {
    switch (activeSection) {
      case AppSection.TREE:
        return <FamilyTree 
          root={appData.familyTree} 
          isAdmin={isAdmin} 
          onEditMember={(m) => {
            // Migrating legacy spouse for editing
            const memberToEdit = {...m};
            if (memberToEdit.spouseName && (!memberToEdit.spouses || memberToEdit.spouses.length === 0)) {
               memberToEdit.spouses = [{ id: 'legacy-' + m.id, name: memberToEdit.spouseName, deathDate: memberToEdit.spouseDeathDate }];
            }
            setEditingMember(memberToEdit);
          }} 
          onDeleteMember={deleteMember}
          onAddChild={(p) => {
            const newChild: FamilyMember = { id: `m-${Date.now()}`, name: 'Thành viên mới', generation: p.generation + 1, isMale: true };
            const addNode = (node: FamilyMember): FamilyMember => {
              if (node.id === p.id) return { ...node, children: [...(node.children || []), newChild] };
              if (node.children) return { ...node, children: node.children.map(addNode) };
              return node;
            };
            updateData({ familyTree: addNode(appData.familyTree) });
            setEditingMember(newChild);
          }} 
        />;
      case AppSection.EVENTS:
        return <Events events={allEvents} isAdmin={isAdmin} onAddEvent={(e) => updateData({ events: [...appData.events, e] })} onDeleteEvent={(id) => updateData({ events: appData.events.filter(ev => ev.id !== id) })} />;
      case AppSection.NEWS:
        return (
          <div className="animate-fadeIn space-y-12">
            <h2 className="text-5xl font-traditional text-primary font-bold text-center">Tin Tức</h2>
            {isAdmin && (
              <div className="flex justify-center"><button onClick={() => setEditingNews({ id: Date.now().toString(), title: '', date: new Date().toLocaleDateString('vi-VN'), summary: '', content: '' })} className="bg-primary text-white px-10 py-4 rounded-full font-black shadow-xl">Soạn tin mới</button></div>
            )}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
              {appData.news.map((item) => (
                <div key={item.id} className="bg-white rounded-3xl shadow-lg overflow-hidden group border border-red-900/5">
                  <div className="h-64 bg-gray-100 relative">
                    <img src={item.imageUrl || 'https://picsum.photos/seed/clan/800/400'} className="w-full h-full object-cover" alt={item.title} />
                    {isAdmin && (
                      <div className="absolute top-4 right-4 flex gap-2"><button onClick={() => setEditingNews(item)} className="bg-white/90 p-2 rounded-full">✏️</button><button onClick={() => setNewsToDelete(item)} className="bg-white/90 p-2 rounded-full">🗑️</button></div>
                    )}
                  </div>
                  <div className="p-8">
                    <span className="text-[10px] font-black text-primary uppercase">{item.date}</span>
                    <h3 className="text-2xl font-traditional font-bold mt-2 mb-4">{item.title}</h3>
                    <p className="text-gray-600 text-sm mb-6">{item.summary}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case AppSection.CHRONICLES:
        return (
          <div className="max-w-4xl mx-auto animate-fadeIn">
            <div className="paper-texture p-10 md:p-20 shadow-2xl rounded-sm border-[12px] border-double border-red-900/10">
              <div className="flex justify-between items-center mb-10 border-b-4 border-red-900/5 pb-8">
                <h2 className="text-5xl font-traditional italic font-black">Phả Kỹ</h2>
                {isAdmin && <button onClick={() => setIsEditingText(!isEditingText)} className="bg-primary text-gold px-8 py-2 rounded-full text-xs font-black uppercase">{isEditingText ? "Xong" : "Sửa"}</button>}
              </div>
              {isEditingText ? <textarea value={appData.historyText} onChange={(e) => updateData({ historyText: e.target.value })} className="w-full h-96 p-6 border-4 border-gold/10 bg-transparent font-traditional text-lg" /> : <div className="drop-cap whitespace-pre-wrap leading-relaxed text-gray-800 font-traditional text-xl">{appData.historyText}</div>}
            </div>
          </div>
        );
      case AppSection.ANCESTRAL_HOUSE:
        return (
          <div className="max-w-5xl mx-auto animate-fadeIn space-y-12">
            <div className="bg-white rounded-[3rem] shadow-xl overflow-hidden border border-red-900/5">
              <div className="h-[300px] md:h-[500px] relative">
                <img src="https://images.unsplash.com/photo-1598640845355-668b5550dfb0?auto=format&fit=crop&q=80&w=1600" className="w-full h-full object-cover" alt="Từ Đường" />
                <div className="absolute bottom-10 left-10"><h2 className="text-4xl md:text-7xl font-traditional text-white font-black">Từ Đường Dòng Họ</h2><p className="text-gold font-bold text-lg">{appData.address}</p></div>
              </div>
              <div className="p-8 md:p-16">
                 {isEditingText ? <textarea value={appData.ancestralHouseText} onChange={(e) => updateData({ ancestralHouseText: e.target.value })} className="w-full h-40 border p-4 rounded-xl font-traditional text-lg" /> : <p className="text-gray-700 leading-relaxed font-traditional text-xl italic border-l-8 border-gold pl-6 py-4 bg-red-50/20">{appData.ancestralHouseText}</p>}
                 {isAdmin && <button onClick={() => setIsEditingText(!isEditingText)} className="mt-8 bg-primary text-gold px-8 py-3 rounded-full font-black uppercase text-xs">{isEditingText ? "Lưu" : "Sửa nội dung"}</button>}
              </div>
            </div>
          </div>
        );
      case AppSection.REGULATIONS:
        return (
          <div className="max-w-4xl mx-auto animate-fadeIn">
            <div className="bg-[#fffcf0] p-10 md:p-16 shadow-2xl rounded-sm border-[16px] border-double border-gray-900/10 text-center">
               <h2 className="text-4xl md:text-6xl font-traditional text-primary font-black uppercase mb-12">Tộc Ước</h2>
               {isEditingText ? <textarea value={appData.regulations.join('\n')} onChange={(e) => updateData({ regulations: e.target.value.split('\n') })} className="w-full h-80 border p-4 font-traditional text-lg" /> : <div className="space-y-6 text-left max-w-2xl mx-auto">{appData.regulations.map((reg, idx) => (<div key={idx} className="flex gap-4 items-start group"><div className="w-10 h-10 bg-primary text-gold rounded-full flex items-center justify-center font-black text-lg shadow-lg">{idx + 1}</div><p className="text-xl text-gray-900 font-traditional font-bold italic border-b border-gold/10 pb-2 flex-1">{reg}</p></div>))}</div>}
               {isAdmin && <button onClick={() => setIsEditingText(!isEditingText)} className="mt-8 bg-primary text-gold px-10 py-3 rounded-full font-black uppercase text-xs">{isEditingText ? "Lưu" : "Sửa Tộc Ước"}</button>}
            </div>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div className="min-h-screen pb-32">
      {isAdmin && (
        <AdminPanel cloudLink={cloudLink} theme={appData.theme || 'tet'} onCloudLinkChange={(l) => { setCloudLink(l); localStorage.setItem('cloud_data_link', l); }} onThemeChange={(t) => updateData({ theme: t })} onExport={() => { navigator.clipboard.writeText(JSON.stringify(appData, null, 2)); showToast("Đã sao chép JSON!"); }} onLogout={() => setIsAdmin(false)} />
      )}
      <div className="bg-primary text-gold text-[10px] py-1.5 text-center font-black tracking-[0.4em] uppercase border-b border-gold/20">Gia Phả Trực Tuyến - {appData.clanName}</div>
      <header className="relative w-full h-[250px] md:h-[450px] flex items-center justify-center bg-black overflow-hidden shadow-2xl">
        <img src={appData.bannerUrl} className="absolute inset-0 w-full h-full object-cover opacity-60" alt="Banner" />
        <div className="absolute bottom-4 right-4 flex gap-2 z-30">
           {isAdmin && <button onClick={() => setShowBannerEdit(true)} className="bg-white/90 text-red-950 px-4 py-2 rounded-full font-black text-xs uppercase">🖼️ Đổi ảnh</button>}
           <button onClick={handleSync} disabled={isSyncing} className="bg-gold/90 text-red-950 px-4 py-2 rounded-full font-black text-xs uppercase">{isSyncing ? "⌛ Tải..." : "🔄 Cập nhật"}</button>
        </div>
      </header>
      <div className="max-w-7xl mx-auto px-4 mt-[-40px] relative z-20">
        <Navigation activeSection={activeSection} onSectionChange={setActiveSection} />
        <main className="mt-10 md:mt-20">{renderSection()}</main>
      </div>

      {editingMember && (
        <div className="fixed inset-0 bg-black/95 z-[500] flex items-center justify-center p-4 md:p-8 overflow-y-auto backdrop-blur-sm">
          <div className="bg-white p-6 md:p-12 rounded-[2rem] w-full max-w-4xl shadow-2xl border-4 border-gold/20 animate-fadeIn">
            <div className="flex flex-col md:flex-row justify-between items-center border-b pb-6 mb-8 gap-4">
              <h3 className="text-2xl md:text-3xl font-traditional font-bold text-gray-900">Biên tập: {editingMember.name}</h3>
              <div className="flex bg-gray-100 p-1 rounded-xl">
                <button onClick={() => setEditingMember({...editingMember, isMale: true})} className={`px-6 py-2 rounded-lg text-xs font-black uppercase ${editingMember.isMale ? 'bg-primary text-white shadow-md' : 'text-gray-400'}`}>Nam</button>
                <button onClick={() => setEditingMember({...editingMember, isMale: false})} className={`px-6 py-2 rounded-lg text-xs font-black uppercase ${!editingMember.isMale ? 'bg-pink-600 text-white shadow-md' : 'text-gray-400'}`}>Nữ</button>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="space-y-6">
                <h4 className="text-[10px] font-black uppercase tracking-widest text-primary bg-gray-100 px-4 py-2 rounded-lg">Thông tin chính</h4>
                <div className="space-y-4">
                  <div>
                    <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Họ và tên</label>
                    <input type="text" value={editingMember.name} onChange={(e) => setEditingMember({...editingMember, name: e.target.value})} className="w-full border-2 border-gray-100 p-3 rounded-xl focus:border-gold outline-none font-bold" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Năm sinh</label>
                      <input type="text" value={editingMember.birthDate || ''} onChange={(e) => setEditingMember({...editingMember, birthDate: e.target.value})} className="w-full border-2 border-gray-100 p-3 rounded-xl font-medium" />
                    </div>
                    <div>
                      <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Ngày mất (ÂL)</label>
                      <input type="text" value={editingMember.lunarDeathDate || editingMember.deathDate || ''} onChange={(e) => setEditingMember({...editingMember, lunarDeathDate: e.target.value, deathDate: e.target.value})} className="w-full border-2 border-gray-100 p-3 rounded-xl font-medium" />
                    </div>
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                <div className="flex justify-between items-center bg-pink-50 px-4 py-2 rounded-lg">
                   <h4 className="text-[10px] font-black uppercase tracking-widest text-pink-900">Danh sách Vợ / Chồng</h4>
                   <button 
                     onClick={() => setEditingMember({...editingMember, spouses: [...(editingMember.spouses || []), { id: `s-${Date.now()}`, name: '' }]})}
                     className="bg-pink-600 text-white w-6 h-6 rounded-full text-xs hover:scale-110 transition-transform"
                   >+</button>
                </div>

                <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2 scrollbar-hide">
                  {(editingMember.spouses || []).map((s, idx) => (
                    <div key={s.id} className="p-4 bg-pink-50/30 border border-pink-100 rounded-2xl relative">
                      <button 
                        onClick={() => setEditingMember({...editingMember, spouses: editingMember.spouses?.filter(sp => sp.id !== s.id)})}
                        className="absolute -top-2 -right-2 bg-red-500 text-white w-5 h-5 rounded-full text-[10px]"
                      >×</button>
                      <div className="space-y-3">
                        <input 
                          type="text" 
                          value={s.name} 
                          onChange={(e) => {
                            const newSpouses = [...(editingMember.spouses || [])];
                            newSpouses[idx].name = e.target.value;
                            setEditingMember({...editingMember, spouses: newSpouses});
                          }} 
                          className="w-full border p-2 rounded-lg text-sm font-bold" 
                          placeholder="Họ tên vợ/chồng..." 
                        />
                        <input 
                          type="text" 
                          value={s.deathDate || ''} 
                          onChange={(e) => {
                            const newSpouses = [...(editingMember.spouses || [])];
                            newSpouses[idx].deathDate = e.target.value;
                            setEditingMember({...editingMember, spouses: newSpouses});
                          }} 
                          className="w-full border p-2 rounded-lg text-xs" 
                          placeholder="Ngày mất (ÂL)..." 
                        />
                      </div>
                    </div>
                  ))}
                  {(!editingMember.spouses || editingMember.spouses.length === 0) && (
                    <p className="text-center text-xs text-gray-400 italic py-4">Chưa có thông tin vợ/chồng</p>
                  )}
                </div>
              </div>
            </div>

            <div className="flex gap-4 mt-12 pt-8 border-t">
              <button onClick={() => {
                const updateNode = (node: FamilyMember): FamilyMember => {
                  if (node.id === editingMember.id) return editingMember;
                  if (node.children) return { ...node, children: node.children.map(updateNode) };
                  return node;
                };
                updateData({ familyTree: updateNode(appData.familyTree) });
                setEditingMember(null);
                showToast("Đã lưu thay đổi");
              }} className="bg-primary text-gold px-10 py-4 rounded-2xl font-black uppercase shadow-lg flex-1">Lưu</button>
              <button onClick={() => setEditingMember(null)} className="bg-gray-100 text-gray-600 px-10 py-4 rounded-2xl font-black uppercase flex-1">Hủy</button>
            </div>
          </div>
        </div>
      )}

      {showLogin && (
        <div className="fixed inset-0 bg-black/90 z-[300] flex items-center justify-center p-8 backdrop-blur-md">
           <div className="bg-white p-12 rounded-[3rem] border-8 border-gray-900 w-full max-w-md text-center">
              <h3 className="text-4xl font-traditional font-black text-gray-900 mb-8">Admin Login</h3>
              <form onSubmit={handleLogin} className="space-y-6">
                 <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full border-4 border-gray-100 rounded-2xl p-4 text-center text-2xl font-black outline-none" placeholder="••••" />
                 <button type="submit" className="w-full bg-primary text-gold py-4 rounded-2xl font-black uppercase text-sm">Đăng nhập</button>
                 <button type="button" onClick={() => setShowLogin(false)} className="text-gray-400 text-[10px] font-bold uppercase mt-4 block mx-auto">Hủy</button>
              </form>
           </div>
        </div>
      )}

      {toast && (
        <div className={`fixed bottom-10 right-10 z-[500] px-8 py-4 rounded-2xl font-bold shadow-2xl animate-fadeIn flex items-center gap-3 border-2 ${toast.type === 'error' ? 'bg-red-50 text-red-800' : 'bg-green-50 text-green-800'}`}>
          <span>{toast.type === 'error' ? '❌' : '✅'}</span> {toast.message}
        </div>
      )}

      <footer className="mt-40 bg-primary py-24 text-center border-t-8 border-gold">
         <h4 className="text-5xl font-traditional text-gold font-black uppercase mb-8">{appData.clanName}</h4>
         <p className="text-yellow-100 font-serif italic text-xl">"Uống Nước Nhớ Nguồn - Ăn Quả Nhớ Kẻ Trồng Cây"</p>
         {!isAdmin && <button onClick={() => setShowLogin(true)} className="mt-12 text-gold/30 text-[10px] font-black uppercase tracking-[0.5em]">🔒 Quản trị</button>}
      </footer>
    </div>
  );
};

export default App;

export enum AppSection {
  NEWS = 'TIN TỨC',
  TREE = 'PHẢ ĐỒ',
  CHRONICLES = 'PHẢ KỸ',
  ANCESTRAL_HOUSE = 'TỪ ĐƯỜNG',
  REGULATIONS = 'TỘC ƯỚC',
  EVENTS = 'SỰ KIỆN'
}

export type AppTheme = 'classic' | 'tet';

export interface Spouse {
  id: string;
  name: string;
  birthDate?: string;
  deathDate?: string;
}

export interface FamilyMember {
  id: string;
  name: string;
  generation: number;
  birthDate?: string;
  deathDate?: string;
  lunarDeathDate?: string;
  spouseName?: string; // Legacy
  spouseBirthDate?: string; // Legacy
  spouseDeathDate?: string; // Legacy
  spouses?: Spouse[]; // Multi-spouse support
  children?: FamilyMember[];
  bio?: string;
  isMale: boolean;
  parentName?: string;
  otherParentId?: string; // ID of the spouse who is the other parent
}

export interface NewsItem {
  id: string;
  title: string;
  date: string;
  summary: string;
  content: string;
  imageUrl?: string;
}

export type EventType = 'giỗ' | 'sinh nhật' | 'họp mặt' | 'khác';

export interface EventItem {
  id: string;
  title: string;
  solarDate: string;
  lunarDateLabel?: string;
  type: EventType;
  description?: string;
}

export interface AppData {
  news: NewsItem[];
  familyTree: FamilyMember;
  events: EventItem[];
  bannerUrl: string;
  address: string;
  historyText: string;
  ancestralHouseText: string;
  regulations: string[];
  clanName: string;
  lastUpdated: string;
  theme?: AppTheme;
}

import React, { useState, useEffect, useMemo } from 'react';
import { AppSection, FamilyMember, NewsItem, EventItem, AppData, Spouse } from './types';
import Navigation from './components/Navigation';
import FamilyTree from './components/FamilyTree';
import Events from './components/Events';
import AdminPanel from './components/AdminPanel';
import { PersistenceService } from './services/persistenceService';
import { 
  CLAN_NAME, CLAN_ADDRESS, SAMPLE_NEWS, SAMPLE_FAMILY_TREE 
} from './constants';

const DEFAULT_CLOUD_LINK = "https://docs.google.com/document/d/17fVZaOxx8s-gS3tFE3nj1fdmSJdYWw0mi_ar45TUoQw/edit?usp=sharing";

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<AppSection>(AppSection.TREE);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
  const [cloudLink, setCloudLink] = useState<string>(() => localStorage.getItem('cloud_data_link') || DEFAULT_CLOUD_LINK);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [password, setPassword] = useState('');
  const [editingMember, setEditingMember] = useState<FamilyMember | null>(null);
  const [editingNews, setEditingNews] = useState<NewsItem | null>(null);
  const [newsToDelete, setNewsToDelete] = useState<NewsItem | null>(null);
  const [isEditingText, setIsEditingText] = useState(false);
  const [showBannerEdit, setShowBannerEdit] = useState(false);

  const [appData, setAppData] = useState<AppData>(() => {
    const saved = PersistenceService.loadLocal();
    if (saved) return saved;
    return {
      news: SAMPLE_NEWS,
      familyTree: SAMPLE_FAMILY_TREE,
      events: [{ id: 'e1', title: 'Họp Mặt Đầu Xuân', solarDate: '2025-02-15', type: 'họp mặt' }],
      bannerUrl: "https://images.unsplash.com/photo-1577908581023-95245842c8d2?auto=format&fit=crop&q=80&w=2000",
      address: CLAN_ADDRESS,
      historyText: "Lịch sử dòng họ Lê là một hành trình dài...",
      ancestralHouseText: "Từ đường là nơi thờ tự linh thiêng...",
      regulations: ["Tôn thờ tổ tiên...", "Đoàn kết..."],
      clanName: CLAN_NAME,
      lastUpdated: new Date().toISOString(),
      theme: 'tet'
    };
  });

  const derivedGioEvents = useMemo(() => {
    const gioList: EventItem[] = [];
    const traverse = (member: FamilyMember) => {
      if (member.lunarDeathDate || member.deathDate) {
        gioList.push({ id: `gio-${member.id}`, title: `Giỗ cụ ${member.name}`, solarDate: '', lunarDateLabel: member.lunarDeathDate || member.deathDate, type: 'giỗ' });
      }
      const spouses = member.spouses || (member.spouseName ? [{ id: 'legacy', name: member.spouseName, deathDate: member.spouseDeathDate }] : []);
      spouses.forEach((s, idx) => {
        if (s.deathDate) {
          gioList.push({ id: `gio-s-${member.id}-${idx}`, title: `Giỗ cụ bà (Vợ ${idx + 1} cụ ${member.name})`, solarDate: '', lunarDateLabel: s.deathDate, type: 'giỗ' });
        }
      });
      member.children?.forEach(traverse);
    };
    traverse(appData.familyTree);
    return gioList;
  }, [appData.familyTree]);

  const allEvents = useMemo(() => [...appData.events, ...derivedGioEvents], [appData.events, derivedGioEvents]);

  useEffect(() => { document.body.className = appData.theme === 'classic' ? 'theme-classic' : ''; }, [appData.theme]);
  useEffect(() => { PersistenceService.saveLocal(appData); }, [appData]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3500);
  };

  const handleSync = async () => {
    setIsSyncing(true);
    const cloudData = await PersistenceService.fetchFromCloud(cloudLink);
    if (cloudData) { setAppData(cloudData); showToast("Đồng bộ thành công!"); }
    setIsSyncing(false);
  };

  const updateData = (updates: Partial<AppData>) => {
    setAppData(prev => ({ ...prev, ...updates, lastUpdated: new Date().toISOString() }));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin123') { setIsAdmin(true); setShowLogin(false); setPassword(''); showToast("Chế độ Quản trị đã mở"); }
    else showToast("Sai mật khẩu!", "error");
  };

  // Robust Recursive Deletion
  const deleteMember = (id: string) => {
    if (id === appData.familyTree.id) {
      showToast("Không thể xoá Cụ Tổ!", "error");
      return;
    }

    const removeRecursive = (node: FamilyMember): FamilyMember => {
      if (!node.children) return node;
      return {
        ...node,
        children: node.children
          .filter(child => child.id !== id)
          .map(removeRecursive)
      };
    };

    const newTree = removeRecursive(appData.familyTree);
    updateData({ familyTree: newTree });
    showToast("Đã xoá thành viên khỏi phả hệ");
  };

  const updateMemberInTree = (updatedMember: FamilyMember) => {
    const updateRecursive = (node: FamilyMember): FamilyMember => {
      if (node.id === updatedMember.id) return updatedMember;
      if (!node.children) return node;
      return {
        ...node,
        children: node.children.map(updateRecursive)
      };
    };
    updateData({ familyTree: updateRecursive(appData.familyTree) });
  };

  const addChildToMember = (parentId: string) => {
    const newChild: FamilyMember = {
      id: `m-${Date.now()}`,
      name: 'Thành viên mới',
      generation: 0, // Will be set by logic
      isMale: true,
      children: []
    };

    const addRecursive = (node: FamilyMember): FamilyMember => {
      if (node.id === parentId) {
        newChild.generation = node.generation + 1;
        return {
          ...node,
          children: [...(node.children || []), newChild]
        };
      }
      if (!node.children) return node;
      return {
        ...node,
        children: node.children.map(addRecursive)
      };
    };

    const newTree = addRecursive(appData.familyTree);
    updateData({ familyTree: newTree });
    setEditingMember(newChild);
  };

  const renderSection = () => {
    switch (activeSection) {
      case AppSection.TREE:
        return <FamilyTree 
          root={appData.familyTree} 
          isAdmin={isAdmin} 
          onEditMember={(m) => {
            const memberToEdit = {...m};
            // Ensure legacy spouse is mapped if needed
            if (memberToEdit.spouseName && (!memberToEdit.spouses || memberToEdit.spouses.length === 0)) {
               memberToEdit.spouses = [{ id: 'legacy-' + m.id, name: memberToEdit.spouseName, deathDate: memberToEdit.spouseDeathDate }];
            }
            setEditingMember(memberToEdit);
          }} 
          onDeleteMember={deleteMember}
          onAddChild={(p) => addChildToMember(p.id)} 
        />;
      case AppSection.EVENTS:
        return <Events events={allEvents} isAdmin={isAdmin} onAddEvent={(e) => updateData({ events: [...appData.events, e] })} onDeleteEvent={(id) => updateData({ events: appData.events.filter(ev => ev.id !== id) })} />;
      case AppSection.NEWS:
        return (
          <div className="animate-fadeIn space-y-12">
            <h2 className="text-5xl font-traditional text-primary font-bold text-center">Tin Tức Dòng Họ</h2>
            {isAdmin && (
              <div className="flex justify-center"><button onClick={() => setEditingNews({ id: Date.now().toString(), title: '', date: new Date().toLocaleDateString('vi-VN'), summary: '', content: '' })} className="bg-primary text-white px-10 py-4 rounded-full font-black shadow-xl hover:scale-105 transition-transform">Soạn tin mới</button></div>
            )}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
              {appData.news.map((item) => (
                <div key={item.id} className="bg-white rounded-3xl shadow-lg overflow-hidden group border border-red-900/5 hover:shadow-2xl transition-all">
                  <div className="h-64 bg-gray-100 relative">
                    <img src={item.imageUrl || 'https://picsum.photos/seed/clan/800/400'} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" alt={item.title} />
                    {isAdmin && (
                      <div className="absolute top-4 right-4 flex gap-2"><button onClick={() => setEditingNews(item)} className="bg-white/95 p-2 rounded-full shadow-lg">✏️</button><button onClick={() => setNewsToDelete(item)} className="bg-white/95 p-2 rounded-full shadow-lg text-red-600">🗑️</button></div>
                    )}
                  </div>
                  <div className="p-8">
                    <span className="text-[10px] font-black text-primary uppercase tracking-widest">{item.date}</span>
                    <h3 className="text-2xl font-traditional font-bold mt-2 mb-4 group-hover:text-primary transition-colors">{item.title}</h3>
                    <p className="text-gray-600 text-sm mb-6 line-clamp-3">{item.summary}</p>
                    <button className="text-[10px] font-black uppercase text-primary tracking-widest border-b-2 border-primary/20 pb-1">Xem chi tiết</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case AppSection.CHRONICLES:
        return (
          <div className="max-w-4xl mx-auto animate-fadeIn">
            <div className="paper-texture p-10 md:p-20 shadow-2xl rounded-sm border-[12px] border-double border-red-900/10 relative">
              <div className="flex justify-between items-center mb-10 border-b-4 border-red-900/5 pb-8">
                <h2 className="text-5xl font-traditional italic font-black">Phả Kỹ</h2>
                {isAdmin && <button onClick={() => setIsEditingText(!isEditingText)} className="bg-primary text-gold px-8 py-2 rounded-full text-xs font-black uppercase">{isEditingText ? "Xong" : "Sửa"}</button>}
              </div>
              {isEditingText ? <textarea value={appData.historyText} onChange={(e) => updateData({ historyText: e.target.value })} className="w-full h-96 p-6 border-4 border-gold/10 bg-transparent font-traditional text-lg leading-relaxed focus:border-gold outline-none" /> : <div className="drop-cap whitespace-pre-wrap leading-relaxed text-gray-800 font-traditional text-xl">{appData.historyText}</div>}
            </div>
          </div>
        );
      default: return <div className="text-center py-20 text-gray-400 font-bold uppercase tracking-widest">Đang phát triển...</div>;
    }
  };

  return (
    <div className="min-h-screen pb-32">
      {isAdmin && (
        <AdminPanel cloudLink={cloudLink} theme={appData.theme || 'tet'} onCloudLinkChange={(l) => { setCloudLink(l); localStorage.setItem('cloud_data_link', l); }} onThemeChange={(t) => updateData({ theme: t })} onExport={() => { navigator.clipboard.writeText(JSON.stringify(appData, null, 2)); showToast("Đã sao chép JSON!"); }} onLogout={() => setIsAdmin(false)} />
      )}
      <div className="bg-primary text-gold text-[10px] py-1.5 text-center font-black tracking-[0.4em] uppercase border-b border-gold/20">Gia Phả Trực Tuyến - {appData.clanName}</div>
      <header className="relative w-full h-[250px] md:h-[450px] flex items-center justify-center bg-black overflow-hidden shadow-2xl">
        <img src={appData.bannerUrl} className="absolute inset-0 w-full h-full object-cover opacity-60" alt="Banner" />
        <div className="relative z-10 text-center px-4">
           <h1 className="text-4xl md:text-8xl font-traditional text-white font-black drop-shadow-2xl animate-fadeIn tracking-tight">{appData.clanName}</h1>
           <p className="text-gold font-script text-2xl md:text-4xl mt-4 opacity-90 drop-shadow-lg italic">Uống nước nhớ nguồn</p>
        </div>
        <div className="absolute bottom-4 right-4 flex gap-2 z-30">
           {isAdmin && <button onClick={() => setShowBannerEdit(true)} className="bg-white/90 text-red-950 px-4 py-2 rounded-full font-black text-xs uppercase shadow-xl hover:bg-white">🖼️ Đổi ảnh</button>}
           <button onClick={handleSync} disabled={isSyncing} className="bg-gold/90 text-red-950 px-4 py-2 rounded-full font-black text-xs uppercase shadow-xl hover:bg-white">{isSyncing ? "⌛ Tải..." : "🔄 Đồng bộ"}</button>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 mt-[-40px] relative z-20">
        <Navigation activeSection={activeSection} onSectionChange={setActiveSection} />
        <main className="mt-10 md:mt-20">{renderSection()}</main>
      </div>

      {/* OPTIMIZED MEMBER EDIT MODAL */}
      {editingMember && (
        <div className="fixed inset-0 bg-black/95 z-[500] flex items-center justify-center p-4 md:p-8 overflow-y-auto backdrop-blur-md animate-fadeIn">
          <div className="bg-white p-6 md:p-12 rounded-[2.5rem] w-full max-w-5xl shadow-2xl border-4 border-gold/20 relative">
            <button onClick={() => setEditingMember(null)} className="absolute top-6 right-6 text-gray-400 hover:text-red-600 text-3xl transition-colors">×</button>

            <div className="flex flex-col md:flex-row justify-between items-start border-b pb-8 mb-8 gap-6">
              <div>
                <h3 className="text-3xl font-traditional font-black text-gray-900">Thông tin: {editingMember.name || 'Thành viên mới'}</h3>
                <p className="text-primary font-black uppercase text-[10px] tracking-widest mt-1">Thế hệ thứ {editingMember.generation}</p>
              </div>
              <div className="flex bg-gray-100 p-1.5 rounded-2xl">
                <button onClick={() => setEditingMember({...editingMember, isMale: true})} className={`px-8 py-3 rounded-xl text-xs font-black uppercase transition-all ${editingMember.isMale ? 'bg-primary text-white shadow-xl scale-105' : 'text-gray-400'}`}>Nam</button>
                <button onClick={() => setEditingMember({...editingMember, isMale: false})} className={`px-8 py-3 rounded-xl text-xs font-black uppercase transition-all ${!editingMember.isMale ? 'bg-pink-600 text-white shadow-xl scale-105' : 'text-gray-400'}`}>Nữ</button>
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
              {/* SECTION 1: PERSONAL INFO */}
              <div className="space-y-8">
                <h4 className="text-[11px] font-black uppercase tracking-widest text-primary flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-primary"></span> 1. Thông tin cá nhân
                </h4>
                <div className="space-y-5">
                  <div>
                    <label className="text-[10px] font-black uppercase text-gray-400 tracking-wider ml-1">Họ và tên</label>
                    <input type="text" value={editingMember.name} onChange={(e) => setEditingMember({...editingMember, name: e.target.value})} className="w-full bg-gray-50 border-2 border-gray-100 p-4 rounded-2xl focus:border-gold outline-none font-bold text-lg" placeholder="Ví dụ: Lê Văn A" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-[10px] font-black uppercase text-gray-400 tracking-wider ml-1">Năm sinh</label>
                      <input type="text" value={editingMember.birthDate || ''} onChange={(e) => setEditingMember({...editingMember, birthDate: e.target.value})} className="w-full bg-gray-50 border-2 border-gray-100 p-4 rounded-2xl font-bold" placeholder="19xx" />
                    </div>
                    <div>
                      <label className="text-[10px] font-black uppercase text-gray-400 tracking-wider ml-1">Ngày mất (ÂL)</label>
                      <input type="text" value={editingMember.lunarDeathDate || editingMember.deathDate || ''} onChange={(e) => setEditingMember({...editingMember, lunarDeathDate: e.target.value, deathDate: e.target.value})} className="w-full bg-gray-50 border-2 border-gray-100 p-4 rounded-2xl font-bold text-red-900" placeholder="15/1" />
                    </div>
                  </div>
                  <div>
                    <label className="text-[10px] font-black uppercase text-gray-400 tracking-wider ml-1">Tiểu sử ngắn</label>
                    <textarea value={editingMember.bio || ''} onChange={(e) => setEditingMember({...editingMember, bio: e.target.value})} className="w-full bg-gray-50 border-2 border-gray-100 p-4 rounded-2xl font-medium h-24" placeholder="Thông tin thêm..." />
                  </div>
                </div>
              </div>

              {/* SECTION 2: SPOUSES */}
              <div className="space-y-8">
                <div className="flex justify-between items-center">
                   <h4 className="text-[11px] font-black uppercase tracking-widest text-pink-700 flex items-center gap-2">
                     <span className="w-2 h-2 rounded-full bg-pink-600"></span> 2. Vợ / Chồng
                   </h4>
                   <button 
                     onClick={() => setEditingMember({...editingMember, spouses: [...(editingMember.spouses || []), { id: `s-${Date.now()}`, name: '' }]})}
                     className="bg-pink-100 text-pink-700 w-8 h-8 rounded-full flex items-center justify-center font-bold hover:bg-pink-600 hover:text-white transition-all shadow-sm"
                   >+</button>
                </div>

                <div className="space-y-4 max-h-[450px] overflow-y-auto pr-2 scrollbar-hide">
                  {(editingMember.spouses || []).map((s, idx) => (
                    <div key={s.id} className="p-5 bg-pink-50/50 border-2 border-pink-100/50 rounded-2xl relative group">
                      <button 
                        onClick={() => setEditingMember({...editingMember, spouses: editingMember.spouses?.filter(sp => sp.id !== s.id)})}
                        className="absolute -top-3 -right-3 bg-red-100 text-red-600 w-7 h-7 rounded-full text-sm opacity-0 group-hover:opacity-100 transition-all shadow-md"
                      >×</button>
                      <div className="space-y-4">
                        <input 
                          type="text" 
                          value={s.name} 
                          onChange={(e) => {
                            const newSpouses = [...(editingMember.spouses || [])];
                            newSpouses[idx].name = e.target.value;
                            setEditingMember({...editingMember, spouses: newSpouses});
                          }} 
                          className="w-full bg-white border-b-2 border-pink-200 p-2 outline-none font-bold text-pink-950" 
                          placeholder="Họ tên vợ/chồng..." 
                        />
                        <div className="flex gap-2 items-center">
                          <span className="text-[8px] font-black uppercase text-pink-300">Giỗ ÂL:</span>
                          <input 
                            type="text" 
                            value={s.deathDate || ''} 
                            onChange={(e) => {
                              const newSpouses = [...(editingMember.spouses || [])];
                              newSpouses[idx].deathDate = e.target.value;
                              setEditingMember({...editingMember, spouses: newSpouses});
                            }} 
                            className="flex-1 bg-transparent border-b border-pink-100 p-1 text-xs" 
                            placeholder="Ngày..." 
                          />
                        </div>
                      </div>
                    </div>
                  ))}
                  {(!editingMember.spouses || editingMember.spouses.length === 0) && (
                    <div className="text-center py-10 border-2 border-dashed border-pink-100 rounded-3xl text-pink-300 text-xs italic">Chưa có thông tin hôn phối</div>
                  )}
                </div>
              </div>

              {/* SECTION 3: CHILDREN (LINKING TO SPOUSE) */}
              <div className="space-y-8">
                 <div className="flex justify-between items-center">
                   <h4 className="text-[11px] font-black uppercase tracking-widest text-emerald-700 flex items-center gap-2">
                     <span className="w-2 h-2 rounded-full bg-emerald-600"></span> 3. Con cái
                   </h4>
                   <button 
                     onClick={() => addChildToMember(editingMember.id)}
                     className="bg-emerald-100 text-emerald-700 px-4 py-1.5 rounded-full text-[10px] font-black uppercase hover:bg-emerald-600 hover:text-white transition-all shadow-sm"
                   >Thêm con</button>
                 </div>

                 <div className="space-y-4 max-h-[450px] overflow-y-auto pr-2 scrollbar-hide">
                    {(editingMember.children || []).map((child, idx) => (
                      <div key={child.id} className="p-4 bg-emerald-50/50 border-2 border-emerald-100/30 rounded-2xl flex flex-col gap-3">
                         <div className="flex justify-between items-center">
                            <span className="font-bold text-emerald-950 text-sm truncate max-w-[120px]">{child.name}</span>
                            <button 
                              onClick={() => {
                                const newChildren = [...(editingMember.children || [])];
                                newChildren.splice(idx, 1);
                                setEditingMember({...editingMember, children: newChildren});
                              }}
                              className="text-[10px] font-black text-red-400 hover:text-red-600"
                            >Xoá</button>
                         </div>
                         <div className="flex flex-col gap-1">
                            <label className="text-[8px] font-black uppercase text-emerald-300 tracking-wider">Là con của bà:</label>
                            <select 
                              value={child.otherParentId || ''} 
                              onChange={(e) => {
                                const newChildren = [...(editingMember.children || [])];
                                newChildren[idx] = {...newChildren[idx], otherParentId: e.target.value};
                                setEditingMember({...editingMember, children: newChildren});
                              }}
                              className="w-full bg-white border border-emerald-100 p-2 rounded-xl text-xs font-bold text-emerald-900 outline-none"
                            >
                               <option value="">-- Không xác định --</option>
                               {(editingMember.spouses || []).map(s => (
                                 <option key={s.id} value={s.id}>{s.name || 'Vợ chưa đặt tên'}</option>
                               ))}
                            </select>
                         </div>
                      </div>
                    ))}
                    {(!editingMember.children || editingMember.children.length === 0) && (
                      <div className="text-center py-10 border-2 border-dashed border-emerald-100 rounded-3xl text-emerald-300 text-xs italic">Chưa có thông tin con cái</div>
                    )}
                 </div>
              </div>
            </div>

            <div className="flex flex-col md:flex-row gap-4 mt-16 pt-10 border-t-4 border-gray-50">
              <button 
                onClick={() => {
                  updateMemberInTree(editingMember);
                  setEditingMember(null);
                  showToast("Đã cập nhật gia phả");
                }} 
                className="bg-primary text-gold px-12 py-5 rounded-2xl font-black uppercase shadow-2xl flex-1 hover:brightness-110 active:scale-95 transition-all text-sm tracking-widest"
              >Lưu thay đổi</button>
              <button 
                onClick={() => setEditingMember(null)} 
                className="bg-gray-100 text-gray-500 px-12 py-5 rounded-2xl font-black uppercase flex-1 hover:bg-gray-200 transition-all text-sm tracking-widest"
              >Hủy & Đóng</button>
            </div>
          </div>
        </div>
      )}

      {showLogin && (
        <div className="fixed inset-0 bg-black/90 z-[300] flex items-center justify-center p-8 backdrop-blur-md animate-fadeIn">
           <div className="bg-white p-12 rounded-[3rem] border-8 border-gray-900 w-full max-w-md text-center shadow-2xl">
              <h3 className="text-4xl font-traditional font-black text-gray-900 mb-8">Admin Access</h3>
              <form onSubmit={handleLogin} className="space-y-6">
                 <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full border-4 border-gray-100 rounded-2xl p-5 text-center text-3xl font-black outline-none focus:border-primary transition-all" placeholder="••••" />
                 <button type="submit" className="w-full bg-primary text-gold py-5 rounded-2xl font-black uppercase text-sm tracking-widest shadow-xl">Kích hoạt quản trị</button>
                 <button type="button" onClick={() => setShowLogin(false)} className="text-gray-400 text-[10px] font-black uppercase mt-6 block mx-auto tracking-widest hover:text-primary transition-colors">Hủy bỏ</button>
              </form>
           </div>
        </div>
      )}

      {toast && (
        <div className={`fixed bottom-10 right-10 z-[1000] px-10 py-5 rounded-[2rem] font-black uppercase text-[11px] tracking-widest shadow-[0_20px_50px_rgba(0,0,0,0.3)] animate-fadeIn flex items-center gap-4 border-4 ${toast.type === 'error' ? 'bg-red-50 text-red-800 border-red-200' : 'bg-green-50 text-green-800 border-green-200'}`}>
          <span className="text-lg">{toast.type === 'error' ? '❌' : '✅'}</span> {toast.message}
        </div>
      )}

      <footer className="mt-40 bg-primary py-32 text-center border-t-8 border-gold relative overflow-hidden">
         <div className="absolute inset-0 opacity-5 pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/oriental-tiles.png')] scale-150"></div>
         <h4 className="text-6xl font-traditional text-gold font-black uppercase mb-8 relative z-10">{appData.clanName}</h4>
         <p className="text-yellow-100 font-serif italic text-2xl relative z-10 mb-12">"Cây có cội, nước có nguồn. Người có tổ, có tông mới có ngày hôm nay."</p>
         <div className="w-24 h-1 bg-gold mx-auto mb-12 opacity-30"></div>
         {!isAdmin && <button onClick={() => setShowLogin(true)} className="relative z-10 text-gold/30 text-[10px] font-black uppercase tracking-[0.6em] hover:text-gold transition-colors">🔒 Quản trị dòng họ</button>}
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo, useCallback } from 'react';
import { FamilyMember, Spouse } from '../types';
import * as htmlToImage from 'https://esm.sh/html-to-image';

interface MemberNodeProps {
  member: FamilyMember;
  isAdmin: boolean;
  searchQuery: string;
  onEdit?: (member: FamilyMember) => void;
  onDelete?: (id: string) => void;
  onAddChild?: (parent: FamilyMember) => void;
}

const MemberNode: React.FC<MemberNodeProps> = ({ member, isAdmin, searchQuery, onEdit, onDelete, onAddChild }) => {
  const [isExpanded, setIsExpanded] = useState(true);
  const hasChildren = member.children && member.children.length > 0;

  // Combine legacy spouse and multi-spouses
  const allSpouses = useMemo(() => {
    const list: Partial<Spouse>[] = [...(member.spouses || [])];
    if (member.spouseName && !list.some(s => s.name === member.spouseName)) {
      list.unshift({ id: 'legacy', name: member.spouseName, deathDate: member.spouseDeathDate });
    }
    return list;
  }, [member.spouses, member.spouseName, member.spouseDeathDate]);

  // Find other parent name for visualization
  const otherParentName = useMemo(() => {
    if (!member.otherParentId) return null;
    // We need to look at the parent's spouses, but since we are at the child node, 
    // the parent object isn't directly passed here. 
    // This is a limitation of the current prop structure.
    // For now, we will assume it's stored in a way we can reference if we passed the parent.
    return null; 
  }, [member.otherParentId]);

  const containsMatch = useMemo(() => {
    if (!searchQuery) return false;
    const q = searchQuery.toLowerCase();

    const checkNode = (node: FamilyMember): boolean => {
      if (node.name.toLowerCase().includes(q)) return true;
      if (node.spouses?.some(s => s.name.toLowerCase().includes(q))) return true;
      if (node.spouseName?.toLowerCase().includes(q)) return true;
      if (node.children) return node.children.some(checkNode);
      return false;
    };

    return checkNode(member);
  }, [member, searchQuery]);

  useEffect(() => {
    if (searchQuery && containsMatch) {
      setIsExpanded(true);
    }
  }, [searchQuery, containsMatch]);

  const toggleExpand = () => {
    setIsExpanded(!isExpanded);
  };

  const isCompact = member.generation >= 4;
  const isGen1To2 = member.generation === 1;

  const isNameMatched = searchQuery && member.name.toLowerCase().includes(searchQuery.toLowerCase());

  const renderVerticalName = (name: string) => {
    return name.split(' ').map((word, i) => (
      <span key={i} className="block leading-tight">{word}</span>
    ));
  };

  const nameFontSizeClass = isCompact 
    ? 'text-[13px] leading-tight py-1' 
    : (isGen1To2 ? 'text-2xl md:text-3xl' : 'text-lg md:text-xl');

  return (
    <div className="flex flex-col items-center transition-all duration-500 w-full">
      <div className="relative group flex flex-col items-center justify-center">
        <div className="flex flex-row items-start gap-2 relative z-10">
          {/* Main Member Node */}
          <div className={`
            relative transition-all duration-500 transform 
            ${isCompact 
              ? 'w-16 p-3 rounded-2xl border-2 bg-white shadow-xl' 
              : 'w-48 md:w-64 p-4 md:p-6 rounded-[1.5rem] md:rounded-[2rem] border-4 bg-white shadow-2xl'
            }
            ${member.isMale 
              ? 'border-red-900/40 shadow-red-900/5' 
              : 'border-pink-900/40 shadow-pink-900/5'
            }
            ${isGen1To2 ? 'ring-8 ring-red-900/5 ring-offset-4 border-red-900 bg-red-50/50' : ''}
            ${isNameMatched ? 'ring-4 ring-yellow-400 border-yellow-500 scale-105 z-20 !shadow-[0_0_30px_rgba(234,179,8,0.5)]' : 'group-hover:-translate-y-1 md:group-hover:-translate-y-2'}
          `}>
            {!isCompact && (
              <div className={`absolute -top-3 left-1/2 -translate-x-1/2 px-3 py-0.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-sm z-20 ${member.isMale ? 'bg-red-900 text-white' : 'bg-pink-600 text-white'}`}>
                {member.isMale ? 'Nam' : 'Nữ'}
              </div>
            )}

            {isAdmin && (
              <div className="absolute -top-4 -left-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-all z-30">
                <button 
                  onClick={(e) => { e.stopPropagation(); onEdit?.(member); }}
                  className={`bg-yellow-500 text-white rounded-full p-2 shadow-xl hover:bg-yellow-600 ${isCompact ? 'scale-75' : ''}`}
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" /></svg>
                </button>
                {!isGen1To2 && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); if(confirm(`Xóa ${member.name} và toàn bộ con cháu của người này khỏi phả đồ?`)) onDelete?.(member.id); }}
                    className={`bg-red-600 text-white rounded-full p-2 shadow-xl hover:bg-red-700 ${isCompact ? 'scale-75' : ''}`}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                  </button>
                )}
              </div>
            )}

            <div className={`
              font-bold text-red-950 font-traditional text-center tracking-tight
              ${nameFontSizeClass}
              ${isNameMatched ? 'text-yellow-700' : ''}
            `}>
              {isCompact ? renderVerticalName(member.name) : member.name}
            </div>

            {!isCompact && (
              <div className="mt-2 md:mt-4 space-y-1 text-center">
                {member.birthDate && (
                  <div className="text-[9px] md:text-[10px] text-gray-500 font-bold uppercase tracking-wider">
                    Sinh: <span className="text-red-900/60 italic">{member.birthDate}</span>
                  </div>
                )}
                {(member.deathDate || member.lunarDeathDate) && (
                  <div className="text-[9px] md:text-[10px] text-red-700/80 font-black uppercase tracking-wider">
                    Mất: <span className="italic">{member.lunarDeathDate || member.deathDate} (ÂL)</span>
                  </div>
                )}
                <div className={`text-[8px] md:text-[9px] font-black uppercase tracking-[0.2em] md:tracking-[0.3em] rounded-full py-1 mt-2 md:mt-4 inline-block px-3 md:px-4 ${isGen1To2 ? 'bg-red-900 text-gold shadow-lg' : 'bg-red-50 text-red-900/60'}`}>
                  {isGen1To2 ? 'Cụ Tổ' : `Đời ${member.generation}`}
                </div>
              </div>
            )}

            {isAdmin && (
              <button 
                onClick={(e) => { e.stopPropagation(); onAddChild?.(member); }}
                className={`absolute -bottom-4 -right-4 bg-red-800 text-white rounded-full p-2 shadow-xl hover:bg-red-950 hover:scale-110 z-30 transition-all ${isCompact ? 'scale-75' : ''}`}
                title="Thêm con"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 5a1 1 0 011 1v3h3a1 1 0 110 2h-3v3a1 1 0 11-2 0v-3H6a1 1 0 110-2h3V6a1 1 0 011-1z" clipRule="evenodd" /></svg>
              </button>
            )}
          </div>

          {/* Multiple Spouses */}
          {allSpouses.map((spouse, idx) => {
            const isSpouseMatched = searchQuery && spouse.name?.toLowerCase().includes(searchQuery.toLowerCase());
            return (
              <div key={spouse.id || idx} className={`
                relative transition-all duration-500 transform 
                ${isCompact 
                  ? 'w-16 p-3 rounded-2xl border-2 border-dashed bg-white shadow-lg' 
                  : 'w-48 md:w-64 p-4 md:p-6 rounded-[1.5rem] md:rounded-[2rem] border-4 border-dashed bg-pink-50/20 shadow-xl'
                }
                border-pink-900/20
                ${isSpouseMatched ? 'ring-4 ring-yellow-400 border-yellow-500 scale-105 z-20 !shadow-[0_0_30px_rgba(234,179,8,0.5)]' : 'group-hover:-translate-y-1 md:group-hover:-translate-y-2'}
              `}>
                <div className={`
                  font-bold text-pink-950 font-traditional text-center tracking-tight
                  ${nameFontSizeClass}
                  ${isSpouseMatched ? 'text-yellow-700' : ''}
                `}>
                  {isCompact ? renderVerticalName(spouse.name || '') : spouse.name}
                </div>
                {!isCompact && (
                  <div className="mt-2 md:mt-4 text-center">
                    <div className="text-[8px] md:text-[9px] text-pink-900/60 font-black uppercase tracking-[0.2em]">Vợ / Chồng {allSpouses.length > 1 ? idx + 1 : ''}</div>
                    {spouse.deathDate && (
                      <div className="text-[8px] md:text-[9px] text-pink-700/60 font-bold mt-1">
                        Mất: {spouse.deathDate} (ÂL)
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {hasChildren && (
          <button
            onClick={toggleExpand}
            className={`
              absolute left-1/2 -translate-x-1/2 z-20 w-8 h-8 rounded-full border-2 shadow-2xl flex items-center justify-center transition-all duration-300
              ${isCompact ? '-bottom-5 scale-90' : '-bottom-4'}
              ${isExpanded ? 'bg-red-950 border-gold text-gold rotate-0' : 'bg-gold border-red-950 text-red-950 rotate-180'}
            `}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M14.707 12.707a1 1 0 01-1.414 0L10 9.414l-3.293 3.293a1 1 0 01-1.414-1.414l4-4a1 1 0 011.414 0l4 4a1 1 0 010 1.414z" clipRule="evenodd" /></svg>
          </button>
        )}
      </div>

      {hasChildren && isExpanded && (
        <div className="relative mt-12 md:mt-16 animate-fadeIn w-full flex flex-col items-center">
          <div className={`absolute top-[-48px] md:top-[-64px] left-1/2 -translate-x-1/2 bg-red-900/20 -z-10 w-[4px] h-[48px] md:h-[64px] ${isGen1To2 ? 'w-[6px] bg-red-900/40' : ''}`} />

          <div className="flex flex-row justify-center relative w-full pt-0">
             {member.children?.map((child, index) => {
                const isFirst = index === 0;
                const isLast = index === (member.children?.length ?? 0) - 1;
                const childIsCompact = child.generation >= 4;

                // Extract current parent spouse for visual label
                const motherSpouse = allSpouses.find(s => s.id === child.otherParentId);

                return (
                  <div key={child.id} className={`relative flex flex-col items-center flex-1 ${childIsCompact ? 'px-1' : 'px-4 md:px-6'}`}>
                     {member.children && member.children.length > 1 && (
                        <div className={`
                          absolute top-0 h-[4px] bg-red-900/20
                          ${isFirst ? 'left-1/2 right-0' : isLast ? 'left-0 right-1/2' : 'left-0 right-0'}
                        `}></div>
                     )}
                     <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[4px] h-6 md:h-8 bg-red-900/20 -z-10"></div>

                     {/* Spouse Branch Label */}
                     {motherSpouse && !childIsCompact && (
                       <div className="absolute top-1 left-1/2 -translate-x-1/2 bg-pink-100/80 text-pink-800 text-[6px] md:text-[8px] font-black uppercase px-2 py-0.5 rounded-full z-10 border border-pink-200 shadow-sm whitespace-nowrap">
                         Bà {motherSpouse.name || '?'}
                       </div>
                     )}

                     <div className="mt-6 md:mt-8 w-full flex justify-center">
                       <MemberNode 
                         member={child} 
                         isAdmin={isAdmin} 
                         searchQuery={searchQuery}
                         onEdit={onEdit} 
                         onDelete={onDelete}
                         onAddChild={onAddChild} 
                       />
                     </div>
                  </div>
                );
             })}
          </div>
        </div>
      )}
    </div>
  );
};

interface FamilyTreeProps {
  root: FamilyMember;
  isAdmin: boolean;
  onEditMember: (member: FamilyMember) => void;
  onDeleteMember: (id: string) => void;
  onAddChild: (parent: FamilyMember) => void;
}

const FamilyTree: React.FC<FamilyTreeProps> = ({ root, isAdmin, onEditMember, onDeleteMember, onAddChild }) => {
  const [scale, setScale] = useState(0.6);
  const [searchQuery, setSearchQuery] = useState('');
  const [isPanelOpen, setIsPanelOpen] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);
  const treeRef = useRef<HTMLDivElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);

  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });
  const [isExporting, setIsExporting] = useState(false);
  const initialPinchDistRef = useRef<number | null>(null);

  const handleZoom = useCallback((delta: number, clientX: number, clientY: number) => {
    if (!containerRef.current) return;
    const container = containerRef.current;
    const rect = container.getBoundingClientRect();
    const mouseX = clientX - rect.left;
    const mouseY = clientY - rect.top;
    const contentX = (mouseX + container.scrollLeft) / scale;
    const contentY = (mouseY + container.scrollTop) / scale;

    setScale(prevScale => {
      const newScale = Math.min(Math.max(prevScale * (1 + delta), 0.1), 3.0);
      requestAnimationFrame(() => {
        container.scrollLeft = contentX * newScale - mouseX;
        container.scrollTop = contentY * newScale - mouseY;
      });
      return newScale;
    });
  }, [scale]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const onWheel = (e: WheelEvent) => {
      e.preventDefault();
      const delta = -e.deltaY * 0.001;
      handleZoom(delta, e.clientX, e.clientY);
    };
    container.addEventListener('wheel', onWheel, { passive: false });
    return () => container.removeEventListener('wheel', onWheel);
  }, [handleZoom]);

  const handleMouseDown = (e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('button, input')) return;
    setIsDragging(true);
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !containerRef.current) return;
    const dx = e.clientX - lastMousePos.x;
    const dy = e.clientY - lastMousePos.y;
    containerRef.current.scrollLeft -= dx;
    containerRef.current.scrollTop -= dy;
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => setIsDragging(false);

  const handleTouchStart = (e: React.TouchEvent) => {
    if (e.touches.length === 2) {
      const dist = Math.hypot(e.touches[0].pageX - e.touches[1].pageX, e.touches[0].pageY - e.touches[1].pageY);
      initialPinchDistRef.current = dist;
    } else if (e.touches.length === 1) {
      setLastMousePos({ x: e.touches[0].clientX, y: e.touches[0].clientY });
      setIsDragging(true);
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (e.touches.length === 2 && initialPinchDistRef.current !== null) {
      e.preventDefault();
      const dist = Math.hypot(e.touches[0].pageX - e.touches[1].pageX, e.touches[0].pageY - e.touches[1].pageY);
      const centerX = (e.touches[0].clientX + e.touches[1].clientX) / 2;
      const centerY = (e.touches[0].clientY + e.touches[1].clientY) / 2;
      const zoomFactor = (dist / initialPinchDistRef.current) - 1;
      handleZoom(zoomFactor * 0.5, centerX, centerY);
      initialPinchDistRef.current = dist;
    } else if (e.touches.length === 1 && isDragging && containerRef.current) {
      const touch = e.touches[0];
      const dx = touch.clientX - lastMousePos.x;
      const dy = touch.clientY - lastMousePos.y;
      containerRef.current.scrollLeft -= dx;
      containerRef.current.scrollTop -= dy;
      setLastMousePos({ x: touch.clientX, y: touch.clientY });
    }
  };

  const handleTouchEnd = () => {
    initialPinchDistRef.current = null;
    setIsDragging(false);
  };

  const handleResetView = useCallback(() => {
    if (!containerRef.current || !treeRef.current) return;
    const isMobile = window.innerWidth < 768;
    const initialScale = isMobile ? 0.3 : 0.6;
    setScale(initialScale);
    setTimeout(() => {
      if (!containerRef.current || !treeRef.current) return;
      const cw = containerRef.current.clientWidth;
      const tw = treeRef.current.offsetWidth * initialScale;
      containerRef.current.scrollLeft = (tw - cw) / 2;
      containerRef.current.scrollTop = 0;
    }, 50);
  }, []);

  useEffect(() => {
    const timer = setTimeout(handleResetView, 300);
    return () => clearTimeout(timer);
  }, [handleResetView]);

  const toggleFullScreen = () => {
    if (!wrapperRef.current) return;
    if (!document.fullscreenElement) {
      wrapperRef.current.requestFullscreen().catch(err => console.error(err));
    } else {
      document.exitFullscreen();
    }
  };

  const handleExportPNG = async () => {
    if (!treeRef.current) return;
    try {
      setIsExporting(true);
      const originalScale = scale;
      setScale(1);
      await new Promise(resolve => setTimeout(resolve, 800));
      const dataUrl = await htmlToImage.toPng(treeRef.current, {
        backgroundColor: '#fdf6e3',
        pixelRatio: 2,
        style: { transform: 'scale(1)', transformOrigin: 'top center' }
      });
      const link = document.createElement('a');
      link.download = `phado-le-${new Date().toISOString().split('T')[0]}.png`;
      link.href = dataUrl;
      link.click();
      setScale(originalScale);
    } catch (err) {
      console.error('Export error:', err);
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div 
      ref={wrapperRef}
      className={`relative w-full overflow-hidden bg-white/60 backdrop-blur-xl rounded-[2rem] md:rounded-[3rem] border-2 border-red-900/5 shadow-2xl transition-all duration-500 ${isFullscreen ? 'fixed inset-0 z-[1000] rounded-none border-none' : 'h-[70vh] md:min-h-[850px]'} flex flex-col`}
    >
      {isExporting && (
        <div className="fixed inset-0 z-[500] bg-black/60 backdrop-blur-md flex flex-col items-center justify-center animate-fadeIn">
          <div className="bg-white p-12 rounded-[2rem] shadow-2xl border-8 border-double border-red-900 flex flex-col items-center gap-6">
            <div className="w-16 h-16 border-4 border-red-900 border-t-gold rounded-full animate-spin"></div>
            <p className="font-black text-red-950 uppercase tracking-[0.3em] text-sm">Đang họa Phả Đồ...</p>
          </div>
        </div>
      )}

      <div className={`controls-panel absolute top-4 right-4 md:top-10 md:right-10 z-50 flex flex-col items-end gap-3`}>
        <div className="flex gap-2">
           <button onClick={toggleFullScreen} className="w-10 h-10 md:w-12 md:h-12 bg-white text-red-950 rounded-full flex items-center justify-center shadow-lg border border-red-900/10 hover:scale-110 active:scale-95 transition-all">
             {isFullscreen ? '↙️' : '↗️'}
           </button>
           <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="w-10 h-10 md:w-12 md:h-12 bg-red-950 text-gold rounded-full flex items-center justify-center shadow-lg border border-gold/30 hover:scale-110 active:scale-95 transition-all">
             {isPanelOpen ? '✖️' : '⚙️'}
           </button>
        </div>

        {isPanelOpen && (
          <div className="bg-white/95 backdrop-blur-2xl shadow-2xl rounded-3xl border border-red-900/10 p-5 w-64 md:w-72 flex flex-col gap-5 animate-fadeIn">
             <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-red-950/40 tracking-widest">Tìm kiếm</label>
                <input type="text" placeholder="Nhập tên..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-red-50/50 border-2 border-red-900/5 rounded-xl px-4 py-2 text-sm font-bold text-red-950 outline-none" />
             </div>
             <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-red-950/40 tracking-widest">Tỉ lệ: {Math.round(scale * 100)}%</label>
                <div className="flex gap-2">
                   <button onClick={() => handleZoom(-0.1, window.innerWidth/2, window.innerHeight/2)} className="flex-1 bg-red-50 text-red-900 py-2 rounded-xl font-bold hover:bg-red-100">-</button>
                   <button onClick={() => handleZoom(0.1, window.innerWidth/2, window.innerHeight/2)} className="flex-1 bg-red-50 text-red-900 py-2 rounded-xl font-bold hover:bg-red-100">+</button>
                   <button onClick={handleResetView} className="bg-red-950 text-gold px-4 rounded-xl">⟲</button>
                </div>
             </div>
             <button onClick={handleExportPNG} className="w-full bg-primary text-gold py-3 rounded-xl font-black text-[10px] uppercase tracking-widest shadow-md">Xuất ảnh PNG</button>
          </div>
        )}
      </div>

      <div ref={containerRef} onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp} onTouchStart={handleTouchStart} onTouchMove={handleTouchMove} onTouchEnd={handleTouchEnd} className={`w-full flex-1 overflow-auto scrollbar-hide select-none ${isDragging ? 'cursor-grabbing' : 'cursor-grab'}`}>
        <div ref={treeRef} style={{ transform: `scale(${scale})`, transformOrigin: '0 0', width: 'fit-content', minWidth: '100%', padding: '200px 100vw' }} className="relative transition-transform duration-75 ease-out">
          <div className="flex justify-center w-full">
            <MemberNode member={root} isAdmin={isAdmin} searchQuery={searchQuery} onEdit={onEditMember} onDelete={onDeleteMember} onAddChild={onAddChild} />
          </div>
        </div>
      </div>
      <div className="bg-white/90 border-t border-red-900/5 px-6 py-2 flex justify-between items-center text-[9px] font-bold text-red-950/30 uppercase tracking-widest">
        <span>Lăn chuột hoặc Pinch để Zoom • Kéo để di chuyển • Xoá thành viên (Admin)</span>
        <span className="hidden md:block">Gia Tộc Họ Lê © 2024</span>
      </div>
    </div>
  );
};

export default FamilyTree;

